            aOrbiterJ = (((aWandererJ + RotL64(aPrevious, 13U)) + 0x94ECEC390523C0BFULL) + aPhaseFOrbiterAssignSaltC[(((31U - aIndex) + 17U)) & 31]) + aNonceWordM;
