            aWandererH = aWandererH ^ ((RotL64(aCross, 57U) + aOrbiterK) + RotL64(aOrbiterE, 29U));
            aWandererB = aWandererB + (((RotL64(aPrevious, 23U) + aOrbiterF) + RotL64(aOrbiterE, 19U)) + RotL64(aCarry, 39U));
            aWandererI = aWandererI ^ (((RotL64(aScatter, 42U) + aOrbiterE) + RotL64(aOrbiterJ, 39U)) + aPhaseBWandererUpdateSaltC[((aIndex + 5U)) & 31]);
            aWandererJ = aWandererJ + ((RotL64(aIngress, 11U) + RotL64(aOrbiterK, 50U)) + aOrbiterF);
