            aOrbiterD = (((aWandererD + RotL64(aCross, 13U)) + RotL64(aCarry, 5U)) + 0x1CD605A75912AFEBULL) + aPhaseDOrbiterAssignSaltE[(((31U - aIndex) + 19U)) & 31];
