            //
            aOrbiterG = (aOrbiterG + aOrbiterE) + 0xD495270E5DFA9CFAULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterG) ^ 0x9E5ED3F827871AD5ULL) ^ aPhaseDOrbiterUpdateSaltB[(((31U - aIndex) + 23U)) & 31];
