            aOrbiterK = RotL64((aOrbiterK * 0xD0D561DFBE7B4189ULL), 3U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterI) + 0x5A135CEC3C7A2B0BULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterE) ^ 0x51184F5DD617B5C8ULL;
            aOrbiterG = RotL64((aOrbiterG * 0xE7146D05A7746237ULL), 11U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterJ) + 0x9D386C993220B49BULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterC) ^ 0xED81C4412E590F89ULL;
            aOrbiterF = RotL64((aOrbiterF * 0xD6E1D0F605A7D9A3ULL), 43U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterC) + 0x74FA5CE7BDC58ED0ULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterK) ^ 0x448971D41D35EE20ULL) ^ aPhaseGOrbiterUpdateSaltF[(((31U - aIndex) + 27U)) & 31];
            aOrbiterI = RotL64((aOrbiterI * 0xE71FC078E84FEAFDULL), 27U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterH) + 0xAEE685C25E971E3CULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterD) ^ 0x6D098B54EAF54125ULL;
