            //
            aIngress = RotL64(aOrbiterD, 11U) ^ aOrbiterA;
            aIngress = aIngress + (aOrbiterB ^ RotL64(aOrbiterC, 60U));
            aIngress = aIngress + (RotL64(aOrbiterE, 43U) ^ aOrbiterJ);
            aIngress = aIngress + (aOrbiterI ^ RotL64(aOrbiterG, 47U));
            aIngress = aIngress + (aOrbiterK ^ RotL64(aOrbiterF, 53U));
            aIngress = aIngress + RotL64(aOrbiterH, 13U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererI = aWandererI ^ ((RotL64(aIngress, 39U) + RotL64(aOrbiterA, 57U)) + aOrbiterJ);
            aWandererA = aWandererA + (((RotL64(aCross, 29U) + aOrbiterH) + RotL64(aOrbiterF, 53U)) + RotL64(aCarry, 23U));
            aWandererB = aWandererB ^ ((RotL64(aScatter, 19U) + aOrbiterF) + RotL64(aOrbiterG, 60U));
            aWandererE = aWandererE + (((RotL64(aPrevious, 47U) + aOrbiterB) + RotL64(aOrbiterG, 5U)) + aPhaseGWandererUpdateSaltD[(((31U - aIndex) + 20U)) & 31]);
