            aWandererF = aWandererF + ((RotL64(aIngress, 37U) + RotL64(aOrbiterB, 37U)) + aOrbiterK);
            aWandererH = aWandererH ^ (((RotL64(aCross, 54U) + aOrbiterG) + RotL64(aOrbiterE, 3U)) + aPhaseGWandererUpdateSaltF[((aIndex + 6U)) & 31]);
            aWandererG = aWandererG + ((RotL64(aPrevious, 43U) + aOrbiterJ) + RotL64(aOrbiterB, 13U));
