            //
            aOrbiterI = ((aWandererE + RotL64(aCross, 11U)) + RotL64(aCarry, 23U)) + 0xBEFA17725E9A38D8ULL;
            aOrbiterD = (aWandererJ + RotL64(aPrevious, 3U)) + 0xB06B52F2C9CBC5AEULL;
            aOrbiterA = (aWandererK + RotL64(aScatter, 29U)) + 0x216A597A0430ED5DULL;
