            aOrbiterF = (aWandererD + RotL64(aIngress, 39U)) + 0x5ABD77A96CD4DE0CULL;
            aOrbiterB = (((aWandererI + RotL64(aPrevious, 27U)) + RotL64(aCarry, 11U)) + 0x14624D26E608DAF3ULL) + aPhaseGOrbiterAssignSaltB[((aIndex + 12U)) & 31];
