            aOrbiterE = (aWandererC + RotL64(aPrevious, 47U)) + 0x5CEAB71A11CB0BC5ULL;
            //
            aOrbiterI = (aOrbiterI + aOrbiterD) + 0xACEE175DF05F24A7ULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterI) ^ 0x0B3D310F9878CC8DULL;
