            //
            aOrbiterH = (aOrbiterH + aOrbiterG) + 0x49F56DB9C47AA25CULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterH) ^ 0x08DC23987DCA28F4ULL;
            aOrbiterD = RotL64((aOrbiterD * 0x92322DFB77458411ULL), 23U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterA) + 0x58C891A6681C17A3ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 0xACE6B5AAE5D7ABB8ULL;
            aOrbiterF = RotL64((aOrbiterF * 0xC08B3C4305C6AFCBULL), 3U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterJ) + 0x7E98EA7C919ECACEULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterD) ^ 0x86C69652B02A4F8AULL;
            aOrbiterB = RotL64((aOrbiterB * 0x348E6431838B5623ULL), 27U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterC) + 0xC5337BB690D92B8AULL) + aPhaseGOrbiterUpdateSaltE[((aIndex + 7U)) & 31];
            aOrbiterH = ((aOrbiterH ^ aOrbiterK) ^ 0xE4495505B934BD0EULL) ^ aPhaseGOrbiterUpdateSaltA[(((31U - aIndex) + 29U)) & 31];
            aOrbiterH = RotL64((aOrbiterH * 0x77CB05722EFC7CE9ULL), 41U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterF) + 0x5D021095A726DEDFULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterB) ^ 0x1232A80AB8DAA384ULL;
            aOrbiterC = RotL64((aOrbiterC * 0xDDF6B72CD419AAD9ULL), 51U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterH) + 0x6F9ECF55F9BD05DFULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterE) ^ 0x3BDF8344A393A11DULL) ^ aPhaseGOrbiterUpdateSaltC[(((31U - aIndex) + 22U)) & 31];
            aOrbiterI = RotL64((aOrbiterI * 0x3D833252AF28AB29ULL), 53U);
