            aOrbiterJ = (aOrbiterJ ^ aOrbiterG) ^ 0x2C6A84F6FCB2A417ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xAAF54771FB4B290DULL), 37U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterK) + 0x416576FCFC1CA77EULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterF) ^ 0x19BA7AB81ADBB032ULL;
            aOrbiterE = RotL64((aOrbiterE * 0xB9E23DCC734D8837ULL), 57U);
