            aWandererK = aWandererK + ((((RotL64(aPrevious, 3U) + RotL64(aOrbiterB, 35U)) + aOrbiterA) + RotL64(aCarry, 19U)) + aPhaseGWandererUpdateSaltB[(((31U - aIndex) + 9U)) & 31]);
